import React, { useState } from "react";
import axios from "axios";
import { motion } from "framer-motion";

const UploadMRI = () => {
  const [file, setFile] = useState(null);
  const [preview, setPreview] = useState("");
  const [result, setResult] = useState("");
  const [loading, setLoading] = useState(false);

  const handleFileChange = (e) => {
    const selectedFile = e.target.files[0];
    setFile(selectedFile);
    if (selectedFile) {
      const reader = new FileReader();
      reader.onloadend = () => setPreview(reader.result);
      reader.readAsDataURL(selectedFile);
    }
  };

  const handleUpload = async () => {
    if (!file) return alert("Please select an image first!");

    const formData = new FormData();
    // formData.append("image", file);
    formData.append("file", file);


    setLoading(true);
    try {
      const response = await axios.post(
        "http://127.0.0.1:8000/api/predict/", // <-- Your Django API endpoint
        formData,
        {
          headers: { "Content-Type": "multipart/form-data" },
        }
      );

      setResult(response.data.result);
    } catch (error) {
      console.error(error);
      alert("Something went wrong! Make sure backend is running.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-screen bg-gradient-to-br from-indigo-100 to-purple-200 p-4">
      <motion.h1
        className="text-3xl font-bold mb-6 text-gray-800"
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
      >
        🧠 Brain Tumor Detection
      </motion.h1>

      <motion.div
        className="bg-white p-8 rounded-2xl shadow-lg w-full max-w-md"
        initial={{ scale: 0.9, opacity: 0 }}
        animate={{ scale: 1, opacity: 1 }}
      >
        <input
          type="file"
          accept="image/*"
          onChange={handleFileChange}
          className="mb-4 w-full border border-gray-300 p-2 rounded-lg"
        />

        {preview && (
          <motion.img
            src={preview}
            alt="Preview"
            className="w-full h-64 object-cover rounded-lg mb-4 border"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
          />
        )}

        <button
          onClick={handleUpload}
          disabled={loading}
          className="w-full bg-indigo-600 text-white py-2 rounded-lg hover:bg-indigo-700 transition"
        >
          {loading ? "Analyzing..." : "Predict Tumor Type"}
        </button>

        {result && (
          <motion.div
            className="mt-6 text-center text-lg font-semibold text-gray-700"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
          >
            Prediction Result:{" "}
            <span className="text-indigo-700">{result}</span>
          </motion.div>
        )}
      </motion.div>
    </div>
  );
};

export default UploadMRI;
